#include <bits/stdc++.h>
using namespace std;
int n , m , ans , sum0[ 3000005 ] , sum1[ 3000005 ] , st[ 21 ][ 3000005 ] , lg[ 3000005 ] , sum = 1 , a[ 3000005 ] ,pre[ 3000005 ];
void init_st() {
	lg[ 1 ] = 0;
	for( int i = 2 ; i <= n ; i++ )
	    lg[ i ] = lg[ i / 2 ] + 1;
	for( int k = 1 ; k <= lg[ n ] ; k++ ) {
		for( int j = 1 ; j + ( 1 << k ) - 1 <= n ; j++ ) {
			st[ k ][ j ] = max( st[ k - 1 ][ j ] , st[ k - 1 ][ j + ( 1 << ( k - 1 ) ) ] );
		}
	}
}
int rmq_st( int l , int r ) {
	int k = lg[r - l + 1 ];
	return max(st[ k ][ r - ( 1 << k ) + 1 ] , st[ k ][ l ]);
}
int main() {
	ios::sync_with_stdio(0);
	cin.tie(0) , cout.tie(0);
	cin >> n >> m;
	for( int i = 1 ; i <= n ; i++ )
	    cin >> a[ i ];
	for( int i = 1 ; i <= n ; i++ ) {
		if( a[ i ] == 1 )
		    sum1[ i ] = sum1[ i - 1 ] + 1;
		else
		    sum1[ i ] = sum1[ i - 1 ];
	}
	for( int i = 1 ; i <= n ; i++ ) {
		if( a[ i ] == 0 )
		    sum0[ i ] = sum0[ i - 1 ] + 1;
		else
		    sum0[ i ] = sum0[ i - 1 ];
	}
	for( int i = 1 ; i <= n ; i++ )
	    st[ 0 ][ i ] = sum0[ i ] - sum1[ i ];
	for( int i = 2 ; i <= n ; i++ ) {
		if( a[ i ] == 1 && a[ i - 1 ] == 0 )
		    pre[ i ] = pre[ i - 1 ] + 1;
		else
		    pre[ i ] = pre[ i - 1 ];
	}
	init_st();
	for( int i = 1 ; i <= m ; i++ ) {
		int l , r , w;
		cin >> w >> l >> r;
		if( w == 1) {
			ans = max( sum0[ r ] - sum0[ l - 1 ] , sum1[ r ] - sum1[ l - 1 ] );
		    ans = max( ans , rmq_st( l , r ) - sum0[ l - 1 ] + sum1[ r ] );
		}
		else {
		    if( pre[ r ] == pre[ l ] )
		        ans = 1;
		    else
		        ans = 2;
		}
		cout << ans << '\n';
	}
    return 0;
}
